import java.io.*;import java.util.*;class Main{static final long MOD=1_000_000_007L;static long one(char c){if(c=='*')return 9;if(c=='0')return 0;return 1;}static long two(char a,char b){if(a=='*'&&b=='*')return 15;if(a=='*')return b<='6'?2:1;if(b=='*'){if(a=='1')return 9;if(a=='2')return 6;return 0;}int v=(a-'0')*10+(b-'0');return 10<=v&&v<=26?1:0;}static long solve(String s){long prev2=1,prev1=one(s.charAt(0));for(int i=1;i<s.length();i++){long cur=(one(s.charAt(i))*prev1+two(s.charAt(i-1),s.charAt(i))*prev2)%MOD;prev2=prev1;prev1=cur;}return prev1;}public static void main(String[] a)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[] d=text.split("\\s+");int t=Integer.parseInt(d[0]);StringBuilder out=new StringBuilder();for(int i=1;i<=t;i++){if(i>1)out.append("\n\n");out.append(solve(d[i]));}System.out.print(out);}}
